const { Worker } = require('cloudflare-worker');
const fetch = require('node-fetch');
const FormData = require('form-data');

// Set up API keys and secrets for SendGrid and Stripe
const sendgridApiKey = 'YOUR_SENDGRID_API_KEY';
const stripeSecretKey = 'YOUR_STRIPE_SECRET_KEY';

// Create a new Worker
const worker = new Worker();

// Define the routes for the Worker
worker.route('POST', '/send-email', async (request) => {
  // Validate the request body and headers
  const { email, subject, message } = request.body;
  if (!email || !subject || !message) {
    return new Response('Missing required parameters', { status: 400 });
  }

  // Authenticate with SendGrid using the API key
  const sendgridAuth = `Bearer ${sendgridApiKey}`;

  // Create a new FormData object for the email request body
  const formData = new FormData();
  formData.append('from', 'YOUR_SENDGRID_FROM_EMAIL');
  formData.append('to', email);
  formData.append('subject', subject);
  formData.append('text', message);

  // Send the email request to SendGrid using the API key and FormData object
  const response = await fetch(`https://api.sendgrid.com/v3/mail/send`, {
    method: 'POST',
    headers: { Authorization: sendgridAuth },
    body: formData,
  });

  // Return the SendGrid response as a JSON object
  return new Response(response.json(), { status: 200 });
});

worker.route('POST', '/charge-payment', async (request) => {
  // Validate the request body and headers
  const { amount, currency } = request.body;
  if (!amount || !currency) {
    return new Response('Missing required parameters', { status: 400 });
  }

  // Authenticate with Stripe using the secret key
  const stripeAuth = `Bearer ${stripeSecretKey}`;

  // Create a new FormData object for the payment request body
  const formData = new FormData();
  formData.append('amount', amount);
  formData.append('currency', currency);

  // Send the payment request to Stripe using the API key and FormData object
  const response = await fetch(`https://api.stripe.com/v1/charges`, {
    method: 'POST',
    headers: { Authorization: stripeAuth },
    body: formData,
  });

  // Return the Stripe response as a JSON object
  return new Response(response.json(), { status: 200 });
});

// Deploy the Worker to Cloudflare
worker.deploy();